// Outbound port (defined by core)
public interface StudentRepository {
    Optional<Student> findById(Long id);
    void save(Student student);
}

// Core business (depends only on port)
public class EnrollmentBusiness {
    @Inject private StudentRepository repository; // port

    public void enroll(Long studentId, Long turmaId) {
        Student student = repository.findById(studentId)
            .orElseThrow(() -> new SenaiException("student.not.found"));
        // ... business logic, no JPA/HTTP/JMS knowledge
    }
}

// Outbound adapter (implements port with JPA)
@Stateless
public class StudentJpaRepository implements StudentRepository {
    @PersistenceContext private EntityManager em;

    public Optional<Student> findById(Long id) {
        return Optional.ofNullable(em.find(Student.class, id));
    }
}
